mapper.select:
SELECT * FROM ( SELECT message_id as messageId, room_id as roomId, sender_id as senderId, sender_type as senderType, message_type as messageType, content, DATE_FORMAT(send_at, '%H:%i') as sendAt FROM chat_message WHERE room_id = #{roomId}
AND message_id < #{lastMessageId}
ORDER BY message_id DESC LIMIT 20 ) sub ORDER BY messageId ASC

mapper.update:
UPDATE chat_message
SET is_read = 1
WHERE room_id = #{roomId}
  AND sender_type != #{userType}
  AND is_read = 0

mapper.select:
SELECT room_id as roomId, customer_id as customerId, business_id as businessId
FROM chat_room
WHERE room_id = #{roomId}
